import { useState } from "react";
import Sidebar from "../components/Sidebar";
import KnowledgeBaseForm from "../components/KnowledgeBaseForm";
import BannedPhrasesManager from "../components/BannedPhrasesManager";
import ActionTypesManager from "../components/ActionTypesManager";
import AgentActionsFeed from "../components/AgentActionsFeed";
import FlagsFeed from "../components/FlagsFeed";

const TABS = [
  { id: "kb", label: "Knowledge Base" },
  { id: "phrases", label: "Banned Phrases" },
  { id: "actions", label: "Action Types" },
  { id: "feeds", label: "Live Feeds" },
];

export default function TeamLeadDashboard() {
  const [activeTab, setActiveTab] = useState("kb");

  return (
    <div className="page-bg flex">
      <Sidebar />

      <div className="flex-1 ml-[268px] p-8">
        <div className="max-w-5xl mx-auto">
          <header className="mb-8">
            <h1 className="page-title">Team Lead Dashboard</h1>
            <p className="page-subtitle">
              Manage knowledge base content, compliance rules, and monitor agent activity.
            </p>
          </header>

          <div className="flex flex-wrap gap-2 mb-6 p-1.5 bg-white/60 rounded-card border border-brand-border">
            {TABS.map((tab) => (
              <button
                key={tab.id}
                type="button"
                onClick={() => setActiveTab(tab.id)}
                className={`tab-btn ${
                  activeTab === tab.id ? "tab-btn-active" : "tab-btn-inactive"
                }`}
              >
                {tab.label}
              </button>
            ))}
          </div>

          {activeTab === "kb" && <KnowledgeBaseForm />}
          {activeTab === "phrases" && <BannedPhrasesManager />}
          {activeTab === "actions" && <ActionTypesManager />}
          {activeTab === "feeds" && (
            <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
              <FlagsFeed />
              <AgentActionsFeed />
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
